import fs from 'fs';
import path from 'path';
import { app } from 'electron';

type LogLevel = 'info' | 'warn' | 'error';

let logStream: fs.WriteStream | null = null;
let logFilePath: string | null = null;

const serialize = (value: unknown): string => {
  if (value instanceof Error) {
    return `${value.name}: ${value.message}\n${value.stack ?? ''}`;
  }

  if (typeof value === 'object') {
    try {
      return JSON.stringify(value);
    } catch (error) {
      return `Unserializable object: ${(error as Error).message}`;
    }
  }

  return String(value);
};

const write = (level: LogLevel, args: unknown[]) => {
  const timestamp = new Date().toISOString();
  const message = args.map(serialize).join(' ');
  const line = `[${timestamp}] [${level.toUpperCase()}] ${message}\n`;

  // Mirror to console for local debugging
  if (level === 'error') {
    console.error(message);
  } else if (level === 'warn') {
    console.warn(message);
  } else {
    console.log(message);
  }

  if (!logStream) {
    return;
  }

  logStream.write(line);
};

export const initLogger = () => {
  if (logStream) {
    return logFilePath;
  }

  const logDir = path.join(app.getPath('userData'), 'logs');
  fs.mkdirSync(logDir, { recursive: true });

  const safeTimestamp = new Date().toISOString().replace(/[:.]/g, '-');
  logFilePath = path.join(logDir, `servercompass-main-${safeTimestamp}.log`);
  logStream = fs.createWriteStream(logFilePath, { flags: 'a' });

  write('info', [`Logger initialized. Writing to ${logFilePath}`]);

  return logFilePath;
};

export const logger = {
  info: (...args: unknown[]) => write('info', args),
  warn: (...args: unknown[]) => write('warn', args),
  error: (...args: unknown[]) => write('error', args),
};

export const getLogFilePath = () => logFilePath;
